protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Keep EF8 discriminator property name ("Discriminator" instead of EF9 default "$type")
    // so existing documents remain readable without data migration.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Keep EF8 compound id format ("Blog|1") instead of EF9 default (key-only "1")
    // so existing documents remain accessible by id.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex removed — Cosmos DB provider now throws at startup.
    // Manage indexing via the container's indexing policy in Azure Portal / Bicep / Terraform.
}

